patches.fixed_method:
public Object complete(JsonParser p, DeserializationContext ctxt, PropertyValueBuffer buffer, PropertyBasedCreator creator) throws IOException {
    final int len = _properties.length;
    Object[] values = new Object[len];
    for (int i = 0; i < len; ++i) {
        String typeId = _typeIds[i];
        final ExtTypedProperty extProp = _properties[i];
        if (typeId == null) {
            throw new InputMismatchException("Missing external type id property: " + extProp.getTypePropertyName());
        }
        if (_tokens[i] == null) {
            SettableBeanProperty prop = extProp.getProperty();
            throw new InputMismatchException("Missing property: " + prop.getName() + " for external type id: " + _properties[i].getTypePropertyName());
        }
        values[i] = _deserialize(p, ctxt, i, typeId);
    }
    Object bean = creator.build(ctxt, buffer);
    // third: assign non-creator properties
    for (int i = 0; i < len; ++i) {
        SettableBeanProperty prop = _properties[i].getProperty();
        if (prop.getCreatorIndex() < 0) {
            prop.set(bean, values[i]);
        }
    }
    return bean;
}

